class Solution:
    def minEnd(self, n: int, x: int) -> int:
        m = n - 1
        res = x
        bit = 1
        while m:
            if (x & bit) == 0:
                res |= (m & 1) * bit
                m >>= 1
            bit <<= 1
        return res

